32	/*
33	  This example demonstrates how to call a CUTLASS GEMM kernel and provides a naive reference
34	  matrix multiply kernel to verify its correctness.
35	
36	  The CUTLASS Gemm template is instantiated in the function CutlassSgemmNN. This is kernel computes
37	  the general matrix product (GEMM) using single-precision floating-point arithmetic and assumes
38	  all matrices have column-major layout.
39	
40	  The threadblock tile size is chosen as 128x128x8 which offers good performance for large matrices.
41	  See the CUTLASS Parallel for All blog post for more exposition on the tunable parameters available
42	  in CUTLASS.
43	
44	  https://devblogs.nvidia.com/cutlass-linear-algebra-cuda/
45	
46	  Aside from defining and launching the SGEMM kernel, this example does not use any other components
47	  or utilities within CUTLASS. Such utilities are demonstrated elsewhere in other examples and are
48	  prevalent in the CUTLASS unit tests.
49	
50	  This example has delibrately been kept similar to the basic_gemm example from cutlass-1.3 to
51	  highlight the minimum amount of differences needed to transition to cutlass-2.0.
52	
53	  Cutlass-1.3 sgemm: https://github.com/NVIDIA/cutlass/blob/master/examples/00_basic_gemm/basic_gemm.cu
54	*/
55	
56	// Standard Library includes
57	#include <iostream>
58	#include <sstream>
59	#include <vector>
60	
61	// Helper methods to check for errors
62	#include "helper.h"
63	
64	//
65	// CUTLASS includes needed for single-precision GEMM kernel
66	//
67	
68	// Defines cutlass::gemm::device::Gemm, the generic Gemm computation template class.
69	#include "cutlass/gemm/device/gemm.h"
70	
71	///////////////////////////////////////////////////////////////////////////////////////////////////
72	//
73	// This function defines a CUTLASS GEMM kernel instantiation, constructs its parameters object,
74	// and launches it on the CUDA device.
75	//
76	///////////////////////////////////////////////////////////////////////////////////////////////////
77	
78	/// Define a CUTLASS GEMM template and launch a GEMM kernel.
79	cudaError_t CutlassSgemmNN(
80	  int M,
81	  int N,
82	  int K,
83	  float alpha,
84	  float const *A,
85	  int lda,
86	  float const *B,
87	  int ldb,
88	  float beta,
89	  float *C,
90	  int ldc) {
91	
92	  // Define type definition for single-precision CUTLASS GEMM with column-major
93	  // input matrices and 128x128x8 threadblock tile size (chosen by default).
94	  //
95	  // To keep the interface manageable, several helpers are defined for plausible compositions
96	  // including the following example for single-precision GEMM. Typical values are used as
97	  // default template arguments. See `cutlass/gemm/device/default_gemm_configuration.h` for more details.
98	  //
99	  // To view the full gemm device API interface, see `cutlass/gemm/device/gemm.h`
100	
101	  using ColumnMajor = cutlass::layout::ColumnMajor;
102	
103	  using CutlassGemm = cutlass::gemm::device::Gemm<float,        // Data-type of A matrix
104	                                                  ColumnMajor,  // Layout of A matrix
105	                                                  float,        // Data-type of B matrix
106	                                                  ColumnMajor,  // Layout of B matrix
107	                                                  float,        // Data-type of C matrix
108	                                                  ColumnMajor>; // Layout of C matrix
109	
110	  // Define a CUTLASS GEMM type
111	  CutlassGemm gemm_operator;
112	
113	  // Construct the CUTLASS GEMM arguments object.
114	  //
115	  // One of CUTLASS's design patterns is to define gemm argument objects that are constructible
116	  // in host code and passed to kernels by value. These may include pointers, strides, scalars,
117	  // and other arguments needed by Gemm and its components.
118	  //
119	  // The benefits of this pattern are (1.) a structured, composable strategy for passing host-constructible
120	  // arguments to kernels and (2.) minimized initialization overhead on kernel entry.
121	  //
122	  CutlassGemm::Arguments args({M , N, K},  // Gemm Problem dimensions
123	                              {A, lda},    // Tensor-ref for source matrix A
124	                              {B, ldb},    // Tensor-ref for source matrix B
125	                              {C, ldc},    // Tensor-ref for source matrix C
126	                              {C, ldc},    // Tensor-ref for destination matrix D (may be different memory than source C matrix)
127	                              {alpha, beta}); // Scalars used in the Epilogue
128	
129	  //
130	  // Launch the CUTLASS GEMM kernel.
131	  //
132	  
133	  cutlass::Status status = gemm_operator(args);
134	
135	  //
136	  // Return a cudaError_t if the CUTLASS GEMM operator returned an error code.
137	  //
138	
139	  if (status != cutlass::Status::kSuccess) {
140	    return cudaErrorUnknown;
141	  }
142	
143	  // Return success, if no errors were encountered.
144	  return cudaSuccess;
145	}
146	
147	///////////////////////////////////////////////////////////////////////////////////////////////////
148	//
149	// The source code after this point in the file is generic CUDA using the CUDA Runtime API
150	// and simple CUDA kernels to initialize matrices and compute the general matrix product.
151	//
152	///////////////////////////////////////////////////////////////////////////////////////////////////
153	
154	/// Kernel to initialize a matrix with small integers.
155	__global__ void InitializeMatrix_kernel(
156	  float *matrix,
157	  int rows,
158	  int columns,
159	  int seed = 0) {
160	
161	  int i = threadIdx.x + blockIdx.x * blockDim.x;
162	  int j = threadIdx.y + blockIdx.y * blockDim.y;
163	
164	  if (i < rows && j < columns) {
165	    int offset = i + j * rows;
166	
167	    // Generate arbitrary elements.
168	    int const k = 16807;
169	    int const m = 16;
170	    float value = float(((offset + seed) * k % m) - m / 2);
171	
172	    matrix[offset] = value;
173	  }
174	}
175	
176	/// Simple function to initialize a matrix to arbitrary small integers.
177	cudaError_t InitializeMatrix(float *matrix, int rows, int columns, int seed = 0) {
178	
179	  dim3 block(16, 16);
180	  dim3 grid(
181	    (rows + block.x - 1) / block.x,
182	    (columns + block.y - 1) / block.y
183	  );
184	
185	  InitializeMatrix_kernel<<< grid, block >>>(matrix, rows, columns, seed);
186	
187	  return cudaGetLastError();
188	}
189	
190	///////////////////////////////////////////////////////////////////////////////////////////////////
191	
192	/// Allocates device memory for a matrix then fills with arbitrary small integers.
193	cudaError_t AllocateMatrix(float **matrix, int rows, int columns, int seed = 0) {
194	  cudaError_t result;
195	
196	  size_t sizeof_matrix = sizeof(float) * rows * columns;
197	
198	  // Allocate device memory.
199	  result = cudaMalloc(reinterpret_cast<void **>(matrix), sizeof_matrix);
200	
201	  if (result != cudaSuccess) {
202	    std::cerr << "Failed to allocate matrix: "
203	      << cudaGetErrorString(result) << std::endl;
204	    return result;
205	  }
206	
207	  // Clear the allocation.
208	  result = cudaMemset(*matrix, 0, sizeof_matrix);
209	
210	  if (result != cudaSuccess) {
211	    std::cerr << "Failed to clear matrix device memory: "
212	      << cudaGetErrorString(result) << std::endl;
213	    return result;
214	  }
215	
216	  // Initialize matrix elements to arbitrary small integers.
217	  result = InitializeMatrix(*matrix, rows, columns, seed);
218	
219	  if (result != cudaSuccess) {
220	    std::cerr << "Failed to initialize matrix: "
221	      << cudaGetErrorString(result) << std::endl;
222	    return result;
223	  }
224	
225	  return result;
226	}
227	
228	///////////////////////////////////////////////////////////////////////////////////////////////////
229	
230	/// Naive reference GEMM computation.
231	__global__ void ReferenceGemm_kernel(
232	  int M,
233	  int N,
234	  int K,
235	  float alpha,
236	  float const *A,
237	  int lda,
238	  float const *B,
239	  int ldb,
240	  float beta,
241	  float *C,
242	  int ldc) {
243	
244	  int i = threadIdx.x + blockIdx.x * blockDim.x;
245	  int j = threadIdx.y + blockIdx.y * blockDim.y;
246	
247	  if (i < M && j < N) {
248	    float accumulator = 0;
249	
250	    for (int k = 0; k < K; ++k) {
251	      accumulator += A[i + k * lda] * B[k + j * ldb];
252	    }
253	
254	    C[i + j * ldc] = alpha * accumulator + beta * C[i + j * ldc];
255	  }
256	}
257	
258	/// Reference GEMM computation.
259	cudaError_t ReferenceGemm(
260	  int M,
261	  int N,
262	  int K,
263	  float alpha,
264	  float const *A,
265	  int lda,
266	  float const *B,
267	  int ldb,
268	  float beta,
269	  float *C,
270	  int ldc) {
271	
272	  dim3 block(16, 16);
273	  dim3 grid(
274	    (M + block.x - 1) / block.x,
275	    (N + block.y - 1) / block.y
276	  );
277	
278	  ReferenceGemm_kernel<<< grid, block >>>(M, N, K, alpha, A, lda, B, ldb, beta, C, ldc);
279	
280	  return cudaGetLastError();
281	}
282	
283	///////////////////////////////////////////////////////////////////////////////////////////////////
284	
285	/// Allocate several matrices in GPU device memory and call a single-precision
286	/// CUTLASS GEMM kernel.
287	cudaError_t TestCutlassGemm(int M, int N, int K, float alpha, float beta) {
288	  cudaError_t result;
289	
290	  //
291	  // Define several matrices to be used as operands to GEMM kernels.
292	  //
293	
294	  // Compute leading dimensions for each matrix.
295	  int lda = M;
296	  int ldb = K;
297	  int ldc = M;
298	
299	  // Compute size in bytes of the C matrix.
300	  size_t sizeof_C = sizeof(float) * ldc * N;
301	
302	  // Define pointers to matrices in GPU device memory.
303	  float *A;
304	  float *B;
305	  float *C_cutlass;
306	  float *C_reference;
307	
308	  //
309	  // Allocate matrices in GPU device memory with arbitrary seeds.
310	  //
311	
312	  result = AllocateMatrix(&A, M, K, 0);
313	
314	  if (result !=  cudaSuccess) {
315	    return result;
316	  }
317	
318	  result = AllocateMatrix(&B, K, N, 17);
319	
320	  if (result !=  cudaSuccess) {
321	    cudaFree(A);
322	    return result;
323	  }
324	
325	  result = AllocateMatrix(&C_cutlass, M, N, 101);
326	
327	  if (result != cudaSuccess) {
328	    cudaFree(A);
329	    cudaFree(B);
330	    return result;
331	  }
332	
333	  result = AllocateMatrix(&C_reference, M, N, 101);
334	
335	  if (result != cudaSuccess) {
336	    cudaFree(A);
337	    cudaFree(B);
338	    cudaFree(C_cutlass);
339	    return result;
340	  }
341	
342	  result = cudaMemcpy(C_reference, C_cutlass, sizeof_C, cudaMemcpyDeviceToDevice);
343	
344	  if (result != cudaSuccess) {
345	    std::cerr << "Failed to copy C_cutlass matrix to C_reference: "
346	      << cudaGetErrorString(result) << std::endl;
347	
348	    cudaFree(C_reference);
349	    cudaFree(C_cutlass);
350	    cudaFree(B);
351	    cudaFree(A);
352	
353	    return result;
354	  }
355	
356	  //
357	  // Launch CUTLASS GEMM.
358	  //
359	
360	  result = CutlassSgemmNN(M, N, K, alpha, A, lda, B, ldb, beta, C_cutlass, ldc);
361	
362	  if (result != cudaSuccess) {
363	    std::cerr << "CUTLASS GEMM kernel failed: "
364	      << cudaGetErrorString(result) << std::endl;
365	
366	    cudaFree(C_reference);
367	    cudaFree(C_cutlass);
368	    cudaFree(B);
369	    cudaFree(A);
370	
371	    return result;
372	  }
373	
374	  //
375	  // Verify.
376	  //
377	
378	  // Launch reference GEMM
379	  result = ReferenceGemm(M, N, K, alpha, A, lda, B, ldb, beta, C_reference, ldc);
380	
381	  if (result != cudaSuccess) {
382	    std::cerr << "Reference GEMM kernel failed: "
383	      << cudaGetErrorString(result) << std::endl;
384	
385	    cudaFree(C_reference);
386	    cudaFree(C_cutlass);
387	    cudaFree(B);
388	    cudaFree(A);
389	
390	    return result;
391	  }
392	
393	  // Copy to host and verify equivalence.
394	  std::vector<float> host_cutlass(ldc * N, 0);
395	  std::vector<float> host_reference(ldc * N, 0);
396	
397	  result = cudaMemcpy(host_cutlass.data(), C_cutlass, sizeof_C, cudaMemcpyDeviceToHost);
398	
399	  if (result != cudaSuccess) {
400	    std::cerr << "Failed to copy CUTLASS GEMM results: "
401	      << cudaGetErrorString(result) << std::endl;
402	
403	    cudaFree(C_reference);
404	    cudaFree(C_cutlass);
405	    cudaFree(B);
406	    cudaFree(A);
407	
408	    return result;
409	  }
410	
411	  result = cudaMemcpy(host_reference.data(), C_reference, sizeof_C, cudaMemcpyDeviceToHost);
412	
413	  if (result != cudaSuccess) {
414	    std::cerr << "Failed to copy Reference GEMM results: "
415	      << cudaGetErrorString(result) << std::endl;
416	
417	    cudaFree(C_reference);
418	    cudaFree(C_cutlass);
419	    cudaFree(B);
420	    cudaFree(A);
421	
422	    return result;
423	  }
424	
425	  //
426	  // Free device memory allocations.
427	  //
428	
429	  cudaFree(C_reference);
430	  cudaFree(C_cutlass);
431	  cudaFree(B);
432	  cudaFree(A);
433	
434	  //
435	  // Test for bit equivalence of results.
436	  //
437	
438	  if (host_cutlass != host_reference) {
439	    std::cerr << "CUTLASS results incorrect." << std::endl;
440	
441	    return cudaErrorUnknown;
442	  }
443	
444	  return cudaSuccess;
445	}
446	
447	///////////////////////////////////////////////////////////////////////////////////////////////////
448	
449	/// Entry point to basic_gemm example.
450	//
451	// usage:
452	//
453	//   00_basic_gemm <M> <N> <K> <alpha> <beta>
454	//
455	int main(int argc, const char *arg[]) {
456	
457	  //
458	  // Parse the command line to obtain GEMM dimensions and scalar values.
459	  //
460	
461	  // GEMM problem dimensions.
462	  int problem[3] = { 128, 128, 128 };
463	
464	  for (int i = 1; i < argc && i < 4; ++i) {
465	    std::stringstream ss(arg[i]);
466	    ss >> problem[i - 1];
467	  }
468	
469	  // Scalars used for linear scaling the result of the matrix product.
470	  float scalars[2] = { 1, 0 };
471	
472	  for (int i = 4; i < argc && i < 6; ++i) {
473	    std::stringstream ss(arg[i]);
474	    ss >> scalars[i - 4];
475	  }
476	
477	  //
478	  // Run the CUTLASS GEMM test.
479	  //
480	
481	  cudaError_t result = TestCutlassGemm(
482	    problem[0],     // GEMM M dimension
483	    problem[1],     // GEMM N dimension
484	    problem[2],     // GEMM K dimension
485	    scalars[0],     // alpha
486	    scalars[1]      // beta
487	  );
488	
489	  if (result == cudaSuccess) {
490	    std::cout << "Passed." << std::endl;
491	  }
492	
493	  // Exit.
494	  return result == cudaSuccess ? 0 : -1;
495	}
496	
497	///////////////////////////////////////////////////////////////////////////////////////////////////
